// ===== MODE TEST TEXTE (sans audio) =====

// Question de test
const question =
  "Explique le portage salarial chez IT-STORM en 3 phrases, et comment se passe la facturation.";


const top_k = 4;

return items.map(item => ({
  ...item,
  json: {
    ...(item.json || {}),
    question,
    transcript: question, // ✅ pour compat avec ton RAG actuel
    top_k,
    hasAudio: false,
    mode: "text-test",
  },
}));

// Best Pick robuste : supporte 1 item (jury seul) OU plusieurs items (multi-modèles)
const arr = Array.isArray(items) ? items : [];

if (!arr.length) {
  return [{ json: { answer: "", confidence: 0, sources: [], quotes: [], message: "Aucune réponse." } }];
}

// Petit helper pour scorer
function scoreItem(item) {
  const j = item.json || {};
  const conf = Number(j.confidence ?? 0);
  const text = String(j.answer || j.message || "").trim();
  const len = text.length;

  // score : confiance prime, longueur juste un tie-breaker léger
  return conf * 100 + len / 100;
}

// Si tu n'as qu'un seul item (cas actuel: jury)
if (arr.length === 1) {
  const j = arr[0].json || {};
  return [{
    json: {
      ...j,
      selected_model: j.dbg?.selected_model || j.dbg?.model || j.selected_model,
      comparison: [{
        model: j.dbg?.selected_model || j.dbg?.model || j.selected_model || "unknown",
        confidence: j.confidence ?? null,
        length: String(j.answer || j.message || "").length
      }]
    }
  }];
}

// Cas multi-items (si tu merges plusieurs modèles plus tard)
let best = null;
let bestScore = -1;

for (const it of arr) {
  const s = scoreItem(it);
  if (s > bestScore) {
    bestScore = s;
    best = it;
  }
}

const bj = best?.json || {};
return [{
  json: {
    ...bj,
    selected_model: bj.dbg?.selected_model || bj.dbg?.model || bj.selected_model,
    comparison: arr.map(i => {
      const jj = i.json || {};
      return {
        model: jj.dbg?.selected_model || jj.dbg?.model || jj.selected_model || "unknown",
        confidence: jj.confidence ?? null,
        length: String(jj.answer || jj.message || "").length
      };
    })
  }
}];

// === INPUT ===
// items[0].json.answer : texte brut du RAG jury

const raw = String(items[0].json.answer || "").trim();

// 1️⃣ Normalisation espaces
let text = raw
  .replace(/\s+/g, " ")
  .replace(/\s([.,!?;:])/g, "$1");

// 2️⃣ Découpage en phrases (robuste FR)
let sentences = text
  .split(/(?<=[.!?])\s+/)
  .map(s => s.trim())
  .filter(s => s.length > 0);

// 3️⃣ Dé-doublonnage strict
const seen = new Set();
sentences = sentences.filter(s => {
  const key = s.toLowerCase();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// 4️⃣ Limite à 3 phrases
sentences = sentences.slice(0, 3);

// 5️⃣ Reconstruction finale
const cleanAnswer = sentences.join(" ");

return [{
  json: {
    ...items[0].json,
    answer: cleanAnswer,
    answer_sentences: sentences,
    answer_nb_sentences: sentences.length,
    answer_post_processed: true
  }
}];

function fixUtf8(str) {
  if (!str) return str;

  const map = {
    "Ã©": "é",
    "Ã¨": "è",
    "Ãª": "ê",
    "Ã ": "à",
    "Ã¢": "â",
    "Ã®": "î",
    "Ã´": "ô",
    "Ã»": "û",
    "Ã§": "ç",
    "â€™": "'",
    "â€˜": "'",
    "â€œ": "\"",
    "â€�": "\"",
    "â€“": "–",
    "â€”": "—",
    "Â ": "",
  };

  let out = str;
  for (const [bad, good] of Object.entries(map)) {
    out = out.split(bad).join(good);
  }
  return out;
}

// Appliquer au champ answer
const json = items[0].json;

json.answer = fixUtf8(json.answer);

// Appliquer aussi aux quotes si présentes
if (Array.isArray(json.quotes)) {
  json.quotes = json.quotes.map(q => ({
    ...q,
    quote: fixUtf8(q.quote)
  }));
}

return [{ json }];

const data = items[0].json || {};

const answer = String(data.answer || "").trim();
const confidence =
  typeof data.confidence === "number"
    ? Math.round(data.confidence * 100)
    : null;

// Modèle choisi par le jury
const model =
  data.dbg?.selected_model ||
  data.selected_model ||
  "unknown";

// Construction texte lisible (AVEC retours ligne)
let text = "";
text += "Réponse :\n";
text += answer + "\n\n";

if (confidence !== null) {
  text += `Confiance estimée : ${confidence} %`;
}

// Ajout du modèle choisi
text += `\nModèle choisi : ${model}`;

// Sortie : message lisible
return [
  {
    json: {
      message: text
    }
  }
];

// Convertir (n8n Code node)
// Objectif : produire un binaire stable pour HTTP Request
// - binary.audio (toujours présent)
// - binary.file  (alias optionnel pour compatibilité)
// - json.lang + json.mime + json.filename

const data = items[0].json || {};
const body = data.body || data;

const lang = (body.lang || "fr").toString().trim() || "fr";

// MIME robuste
let mime = (body.mime || body.mimetype || "audio/webm").toString().trim().toLowerCase();
if (!mime.includes("/")) mime = "audio/webm";

// base64 robuste
let b64 = (body.audio_base64 || body.audioBase64 || body.audio || "").toString().trim();
if (!b64) throw new Error("Convertir: audio_base64 manquant");

// support data URL
if (b64.startsWith("data:")) {
  const parts = b64.split("base64,");
  b64 = parts.length > 1 ? parts[1] : "";
}

// nettoyage
const clean = b64.replace(/\s/g, "");
if (!clean) throw new Error("Convertir: base64 vide après nettoyage");

// nom de fichier cohérent
const ext = mime.includes("wav") ? "wav" :
            mime.includes("mpeg") || mime.includes("mp3") ? "mp3" :
            mime.includes("ogg") ? "ogg" :
            mime.includes("mp4") ? "mp4" :
            mime.includes("webm") ? "webm" : "bin";

const filename = `audio.${ext}`;

// construit l'objet binaire n8n
const binObj = {
  data: clean,
  mimeType: mime,
  fileName: filename,
};

// ✅ On fournit 2 clés pour éviter les problèmes dans les HTTP nodes
return [{
  json: { lang, mime, filename },
  binary: {
    audio: binObj, // standard
    file: binObj,  // alias compat (si API attend "file" côté form-data)
  }
}];

const r = items[0].json || {};

return [{
  json: {
    answer: r.answer || "",
    confidence: r.confidence ?? null,
    model: r.dbg?.selected_model ?? null,
    sources: r.sources || []
  }
}];

const body = items[0].json || {};

// accepte plusieurs sources possibles
let text =
  body.text ||
  body.label ||
  body.Label ||
  "";

text = String(text).trim();

if (!text) {
  return [{
    json: {
      error: "Texte vide",
      hint: "Veuillez coller un texte à résumer."
    }
  }];
}

text = text
  .replace(/\r/g, "\n")
  .replace(/[ \t]{2,}/g, " ")
  .replace(/\n{3,}/g, "\n\n")
  .trim();

const timeout = Number(body.timeout || 60);

return [{
  json: {
    text,
    timeout
  }
}];

const j = items[0].json || {};

const answer = (j.answer || "").toString().trim();
const sources = Array.isArray(j.sources) ? j.sources : [];

function cleanText(t){
  return t
    .replace(/\\n/g, "\n")     // si la réponse contient des \n échappés
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

let msg = cleanText(answer);

// Option: ajouter sources en bas (compact)
if (sources.length) {
  msg += "\n\nSources: " + sources.join(" | ");
}

return [{
  json: {
    ...j,
    reply_text: msg
  }
}];
